        # https://github.com/microsoft/Microsoft365DSC/wiki/SCLabelPolicy
        SCLabelPolicy "SCLabelPolicy-AIP_AIP (Pilot)"
        {
            AdvancedSettings      = @(
                MSFT_SCLabelSetting
                {
                    Key   = 'mandatory'
                    Value = 'true'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'attachmentaction'
                    Value = 'Recommended'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'enablecustompermissions'
                    Value = 'false'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'attachmentactiontip'
                    Value = 'It is recommended to label this email as ${Attachment.Label}'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'enableaudit'
                    Value = 'true'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'requiredowngradejustification'
                    Value = 'false'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'hidebarbydefault'
                    Value = 'false'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'disablednf'
                    Value = 'false'
                }
                MSFT_SCLabelSetting
                {
                    Key   = 'outlookdefaultlabel'
